queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?software_developers a :Software_Developers .
    ?software_developers p:name ?name .
    ?software_developers p:grade ?grade_f .
    FILTER(STR(?grade_f) = "Middle")
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?data_analysts a :Data_Analysts .
    ?data_analysts p:name ?name .
    ?data_analysts p:grade ?grade_f .
    FILTER(STR(?grade_f) = "Middle")
    BIND(?name AS ?o0)
  }
}

